import 'package:flutter/material.dart';import 'package:flutter/services.dart';import 'app_colors.dart';import 'app_spacing.dart';import 'app_typography.dart';class DsPrimaryButton extends StatefulWidget {  final String text;  final VoidCallback onPressed;  final bool isLoading;  const DsPrimaryButton({    super.key,    required this.text,    required this.onPressed,    this.isLoading = false,  });  @override  State<DsPrimaryButton> createState() => _DsPrimaryButtonState();}@overrideclass _DsPrimaryButtonState extends State<DsPrimaryButton> with SingleTickerProviderStateMixin {  late AnimationController _controller;  late Animation<double> _scaleAnimation;  late Animation<Color?> _colorAnimation;  @override  void initState() {    super.initState();    _controller = AnimationController(      vsync: this,      duration: const Duration(milliseconds: 150),    );    _scaleAnimation = Tween<double>(begin: 1.0, end: 0.97).animate(      CurvedAnimation(parent: _controller, curve: Curves.easeOut),    );    _colorAnimation = ColorTween(      begin: AppColors.primary,      end: AppColors.buttonHoverPrimary,    ).animate(      CurvedAnimation(parent: _controller, curve: Curves.easeOut),    );  }  @override  void dispose() {    _controller.dispose();    super.dispose();  }  void _onTapDown(TapDownDetails details) {    HapticFeedback.lightImpact();    _controller.forward();  }  void _onTapUp(TapUpDetails details) {    _controller.reverse();  }  void _onTapCancel() {    _controller.reverse();  }  @override  Widget build(BuildContext context) {    return GestureDetector(      onTapDown: _onTapDown,      onTapUp: _onTapUp,      onTapCancel: _onTapCancel,      onTap: widget.isLoading ? null : widget.onPressed,      child: AnimatedBuilder(        animation: _controller,        builder: (context, child) {          return Transform.scale(            scale: _scaleAnimation.value,            child: Opacity(              opacity: _scaleAnimation.value == 0.97 ? 0.85 : 1.0,              child: Container(                height: AppSpacing.buttonHeight,                decoration: BoxDecoration(                  color: _colorAnimation.value,                  borderRadius: BorderRadius.circular(AppSpacing.borderRadiusSmall),                  boxShadow: [                    if (_controller.isAnimating || _controller.isCompleted)                      BoxShadow(                        color: AppColors.primary.withOpacity(0.4),                        blurRadius: 10,                        spreadRadius: 2,                      ),                  ],                ),                child: Center(                  child: widget.isLoading                      ? const SizedBox(                          width: 24,                          height: 24,                          child: CircularProgressIndicator(                            color: AppColors.buttonTextPrimary,                            strokeWidth: 2,                          ),                        )                      : Text(                          widget.text,                          style: AppTypography.button.copyWith(color: AppColors.buttonTextPrimary),                        ),                ),              ),            ),          );        },      ),    );  }}class DsSecondaryButton extends StatefulWidget {  final String text;  final VoidCallback onPressed;  final bool isLoading;  const DsSecondaryButton({    super.key,    required this.text,    required this.onPressed,    this.isLoading = false,  });  @override  State<DsSecondaryButton> createState() => _DsSecondaryButtonState();}@overrideclass _DsSecondaryButtonState extends State<DsSecondaryButton> with SingleTickerProviderStateMixin {  late AnimationController _controller;  late Animation<double> _scaleAnimation;  late Animation<Color?> _backgroundAnimation;  late Animation<Color?> _borderAnimation;  late Animation<Color?> _textAnimation;  @override  void initState() {    super.initState();    _controller = AnimationController(      vsync: this,      duration: const Duration(milliseconds: 150),    );    _scaleAnimation = Tween<double>(begin: 1.0, end: 0.97).animate(      CurvedAnimation(parent: _controller, curve: Curves.easeOut),    );    _backgroundAnimation = ColorTween(      begin: Colors.transparent,      end: AppColors.buttonHoverSecondaryBackground,    ).animate(      CurvedAnimation(parent: _controller, curve: Curves.easeOut),    );    _borderAnimation = ColorTween(      begin: AppColors.buttonBorderSecondary,      end: AppColors.primary,    ).animate(      CurvedAnimation(parent: _controller, curve: Curves.easeOut),    );    _textAnimation = ColorTween(      begin: AppColors.textSecondary,      end: AppColors.primary,    ).animate(      CurvedAnimation(parent: _controller, curve: Curves.easeOut),    );  }  @override  void dispose() {    _controller.dispose();    super.dispose();  }  void _onTapDown(TapDownDetails details) {    HapticFeedback.lightImpact();    _controller.forward();  }  void _onTapUp(TapUpDetails details) {    _controller.reverse();  }  void _onTapCancel() {    _controller.reverse();  }  @override  Widget build(BuildContext context) {    return GestureDetector(      onTapDown: _onTapDown,      onTapUp: _onTapUp,      onTapCancel: _onTapCancel,      onTap: widget.isLoading ? null : widget.onPressed,      child: AnimatedBuilder(        animation: _controller,        builder: (context, child) {          return Transform.scale(            scale: _scaleAnimation.value,            child: Container(              height: AppSpacing.buttonHeight,              decoration: BoxDecoration(                color: _backgroundAnimation.value,                borderRadius: BorderRadius.circular(AppSpacing.borderRadiusSmall),                border: Border.all(color: _borderAnimation.value!, width: 1),                boxShadow: [                  if (_controller.isAnimating || _controller.isCompleted)                    BoxShadow(                      color: AppColors.primary.withOpacity(0