mation = ColorTween(      begin: widget.iconColor ?? AppColors.textSecondary,      end: AppColors.primary,    ).animate(      CurvedAnimation(parent: _controller, curve: Curves.easeOut),    );  }  @override  void dispose() {    _controller.dispose();    super.dispose();  }  void _onTapDown(TapDownDetails details) {    HapticFeedback.lightImpact();    _controller.forward();  }  void _onTapUp(TapUpDetails details) {    _controller.reverse();  }  void _onTapCancel() {    _controller.reverse();  }  @override  Widget build(BuildContext context) {    return GestureDetector(      onTapDown: _onTapDown,      onTapUp: _onTapUp,      onTapCancel: _onTapCancel,      onTap: widget.onPressed,      child: AnimatedBuilder(        animation: _controller,        builder: (context, child) {          return Transform.scale(            scale: _scaleAnimation.value,            child: Container(              width: widget.size,              height: widget.size,              decoration: BoxDecoration(                color: _backgroundAnimation.value,                shape: BoxShape.circle,                boxShadow: [                  if (_controller.isAnimating || _controller.isCompleted)                    BoxShadow(                      color: AppColors.primary.withOpacity(0.2),                      blurRadius: 8,                      spreadRadius: 1,                    ),                ],              ),              child: Icon(                widget.icon,                color: _iconColorAnimation.value,                size: AppSpacing.iconSizeMedium,              ),            ),          );        },      ),    );  }}